const msg = $json;
function getHeader(name) {
  const headers = msg.headers || {};
  if (headers && !Array.isArray(headers) && typeof headers === 'object') {
    const key = Object.keys(headers).find(k => k.toLowerCase() === name.toLowerCase());
    if (key) return String(headers[key] || '');
  }
  const payloadHeaders = msg.payload?.headers;
  if (Array.isArray(payloadHeaders)) {
    const found = payloadHeaders.find(h => String(h.name || '').toLowerCase() === name.toLowerCase());
    return String(found?.value || '');
  }
  return '';
}
function htmlToText(html = '') {
  return String(html).replace(/<style[\s\S]*?<\/style>/gi,' ').replace(/<script[\s\S]*?<\/script>/gi,' ').replace(/<!--[\s\S]*?-->/g,' ').replace(/<br\s*\/?>/gi,'\n').replace(/<\/p>/gi,'\n').replace(/<\/div>/gi,'\n').replace(/<[^>]+>/g,' ').replace(/&nbsp;/gi,' ').replace(/&amp;/gi,'&').replace(/&lt;/gi,'<').replace(/&gt;/gi,'>').replace(/&#39;/gi,"'").replace(/&quot;/gi,'"').replace(/[ \t]+/g,' ').replace(/\n{3,}/g,'\n\n').trim();
}
const from=String(getHeader('from')||msg.from||msg.sender||'').replace(/^From:\s*/i,'').trim();
const subject=String(getHeader('subject')||msg.subject||'').replace(/^Subject:\s*/i,'').trim();
const dateValue=String(getHeader('date')||msg.date||msg.internalDate||new Date().toISOString()).replace(/^Date:\s*/i,'').trim();
const m=from.match(/<([^>]+)>/)||from.match(/[\w.+-]+@[\w.-]+\.[A-Za-z]{2,}/);
const senderEmail=m?(m[1]||m[0]):'';
const senderName=from.replace(/<[^>]+>/g,'').replace(/^"|"$/g,'').trim();
let receivedDate; try { if(/^\d+$/.test(dateValue)) receivedDate=new Date(Number(dateValue)).toISOString(); else { const d=new Date(dateValue); receivedDate=Number.isNaN(d.getTime())?new Date().toISOString():d.toISOString(); } } catch { receivedDate=new Date().toISOString(); }
const emailBody=msg.text||msg.textPlain||htmlToText(msg.html||msg.textHtml||'')||msg.snippet||'';
return [{json:{senderName,senderEmail,subject,receivedDate,messageId:msg.id||msg.messageId||'',threadId:msg.threadId||'',emailBody:String(emailBody).slice(0,30000),processingMode:msg.processingMode||'live'}}];

const data=$json;
function decode(v=''){return String(v).replace(/&nbsp;/gi,' ').replace(/&amp;/gi,'&').replace(/&lt;/gi,'<').replace(/&gt;/gi,'>').replace(/&#39;/gi,"'").replace(/&quot;/gi,'"').replace(/&#x27;/gi,"'").replace(/&#x2F;/gi,'/');}
let text=decode(data.emailBody||'').replace(/<style[\s\S]*?</style>/gi,' ').replace(/<script[\s\S]*?</script>/gi,' ').replace(/<!--[\s\S]*?-->/g,' ').replace(/<br\s*/?>/gi,'
').replace(/</p>/gi,'
').replace(/</div>/gi,'
').replace(/<[^>]+>/g,' ');
text=text.replace(/https?://[^\s<>"']*(?:trk|track|tracking|utm_|click|redirect|unsubscribe)[^\s<>"']*/gi,'[link removed]').replace(/https?://[^\s<>"']{180,}/gi,'[long link removed]').replace(/^\s*unsubscribe.*$/gim,'').replace(/^\s*manage (your )?preferences.*$/gim,'').replace(/^\s*email preferences.*$/gim,'').replace(/^\s*privacy policy.*$/gim,'').replace(/^\s*view (this )?email in (your )?browser.*$/gim,'').replace(/^\s*this email was sent to.*$/gim,'').replace(/^\s*you are receiving this email because.*$/gim,'').replace(//g,'').replace(/[ 	]+/g,' ').replace(/
