').trim();
return [{json:{...data,cleanedEmailBody:text.slice(0,4500)}}];

const source = $('Normalize Email').item.json;
const raw = $json.output ?? $json.deterministicOutput ?? $json;

const allowedStatuses = new Set([
  'Applied',
  'Application Received',
  'Under Review',
  'Recruiter Contacted',
  'Assessment Requested',
  'Interview Requested',
  'Interview Scheduled',
  'Shortlisted',
  'Additional Information Requested',
  'Rejected',
  'Withdrawn',
  'Offer Received',
  'Hired',
  'Unknown'
]);

const clean = value =>
  value == null ? '' : String(value).trim();

function dateOnly(value) {
  const text = clean(value);

  if (!text) {
    return '';
  }

  if (/^\d{4}-\d{2}-\d{2}$/.test(text)) {
    return text;
  }

  const parsed = new Date(text);

  return Number.isNaN(parsed.getTime())
    ? ''
    : parsed.toISOString().slice(0, 10);
}

function slug(value) {
  return clean(value)
    .toLowerCase()
    .normalize('NFKD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/&/g, ' and ')
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .replace(/-+/g, '-');
}

const isQualified =
  raw.isJobApplicationEmail === true;

const confidence = Math.max(
  0,
  Math.min(1, Number(raw.confidence || 0))
);

const applicationStatus =
  allowedStatuses.has(raw.applicationStatus)
    ? raw.applicationStatus
    : 'Unknown';

const companyName = clean(raw.companyName);
const jobTitle = clean(raw.jobTitle);

const companySlug = slug(companyName);
const jobSlug = slug(jobTitle);

const applicationKey =
  companySlug && jobSlug
    ? `${companySlug}--${jobSlug}`
    : '';

const receivedDate =
  source.receivedDate || new Date().toISOString();

const lastActivityDate =
  dateOnly(receivedDate);

const dateApplied =
  dateOnly(raw.dateApplied) ||
  (
    isQualified &&
    ['Applied', 'Application Received'].includes(applicationStatus)
      ? lastActivityDate
      : ''
  );

return [{
  json: {
    isJobApplicationEmail: isQualified,
    confidence,
    applicationKey,
    jobBoard: clean(raw.jobBoard),
    companyName,
    jobTitle,
    jobDescription: clean(raw.jobDescription),
    salaryOffered: clean(raw.salaryOffered),
    jobDatePosted: dateOnly(raw.jobDatePosted),
    dateApplied,
    lastActivityDate,
    applicationStatus,
    recruiterName: clean(raw.recruiterName),
    recruiterEmail:
      clean(raw.recruiterEmail) ||
      clean(source.senderEmail),
    applicationUrl: clean(raw.applicationUrl),
    emailSubject: clean(source.subject),
    receivedDate,
    lastUpdated: new Date().toISOString(),
    messageId: clean(source.messageId),
    reason: clean(raw.reason),
    processingMode:
      source.processingMode ||
      $json.processingMode ||
      'live'
  }
}];

const current = $('Build Application Record').item.json;
const existing = $json || {};

const getExisting = name =>
  existing[name] ??
  existing[name.replace(/\s+/g, '')] ??
  '';

const existingKey = getExisting('Application Key');
const isNewApplication = !existingKey;

const previousStatus = getExisting('Application Status');
const existingLastActivity = getExisting('Last Activity Date');
const currentLastActivity = current.lastActivityDate || '';

const firstNonEmpty = (newValue, oldValue) => {
  const text = newValue == null ? '' : String(newValue).trim();
  return text !== '' ? newValue : (oldValue ?? '');
};

const currentTime = currentLastActivity
  ? new Date(`${currentLastActivity}T00:00:00Z`).getTime()
  : 0;

const existingTime = existingLastActivity
  ? new Date(`${existingLastActivity}T00:00:00Z`).getTime()
  : 0;

const incomingIsOlder =
  current.processingMode === 'backfill' &&
  existingKey &&
  currentTime > 0 &&
  existingTime > 0 &&
  currentTime < existingTime;

const selectedStatus = incomingIsOlder
  ? previousStatus
  : firstNonEmpty(current.applicationStatus, previousStatus);

const selectedLastActivity = incomingIsOlder
  ? existingLastActivity
  : firstNonEmpty(current.lastActivityDate, existingLastActivity);

const merged = {
  ...current,
  applicationKey: current.applicationKey,
  jobBoard: firstNonEmpty(current.jobBoard, getExisting('Job Board')),
  companyName: firstNonEmpty(current.companyName, getExisting('Company Name')),
  jobTitle: firstNonEmpty(current.jobTitle, getExisting('Job Title')),
  jobDescription: firstNonEmpty(current.jobDescription, getExisting('Job Description')),
  salaryOffered: firstNonEmpty(current.salaryOffered, getExisting('Salary Offered')),
  jobDatePosted: firstNonEmpty(current.jobDatePosted, getExisting('Job Date Posted')),
  dateApplied: firstNonEmpty(getExisting('Date Applied'), current.dateApplied),
  lastActivityDate: selectedLastActivity,
  applicationStatus: selectedStatus,
  recruiterName: firstNonEmpty(current.recruiterName, getExisting('Recruiter Name')),
  recruiterEmail: firstNonEmpty(current.recruiterEmail, getExisting('Recruiter Email')),
  applicationUrl: firstNonEmpty(current.applicationUrl, getExisting('Application URL')),
  emailSubject: incomingIsOlder
    ? firstNonEmpty(getExisting('Email Subject'), current.emailSubject)
    : current.emailSubject,
  receivedDate: incomingIsOlder
    ? firstNonEmpty(getExisting('Received Date'), current.receivedDate)
    : current.receivedDate,
  lastUpdated: new Date().toISOString(),
  messageId: incomingIsOlder
    ? firstNonEmpty(getExisting('Message ID'), current.messageId)
    : current.messageId,
  confidence: incomingIsOlder
    ? Number(getExisting('Confidence Score') || current.confidence || 0)
    : current.confidence,
  processingMode: current.processingMode || 'live',
  isNewApplication,
  previousStatus,
  incomingIsOlder,
  statusChanged:
    !isNewApplication &&
    !incomingIsOlder &&
    previousStatus !== '' &&
    previousStatus !== current.applicationStatus
};

return [{ json: merged }];

const item = $json;

function decodeMimeHeader(value = '') {
  // Handles common UTF-8 Base64 encoded words, such as =?UTF-8?B?...?=
  return String(value).replace(
    /=\?UTF-8\?B\?([^?]+)\?=/gi,
    (_, encoded) => {
      try {
        return Buffer.from(encoded, 'base64').toString('utf8');
      } catch {
        return _;
      }
    }
  );
}

const senderName = decodeMimeHeader(item.senderName || '');
const subject = decodeMimeHeader(item.subject || '');
const sender = String(item.senderEmail || '').toLowerCase();
const body = String(item.cleanedEmailBody || '');

const normalizedSubject = subject.toLowerCase();
const normalizedBody = body.toLowerCase();
const text = `${normalizedSubject}\n${sender}\n${normalizedBody.slice(0, 3000)}`;

const strongApplicationEvidence = [
  'application submitted',
  'your application was successfully submitted',
  'application was successfully submitted',
  'successfully submitted',
  'application received',
  'application confirmation',
  'your application has been received',
  'your application has been submitted',
  'application was sent',
  'your application was sent',
  'successfully applied',
  'thank you for applying',
  'thanks for applying',
  'we received your application',
  'we have received your application',
  'regarding your application',
  'application status',
  'application update',
  'application forward update',
  'application has been reviewed',
  'jobs you applied for',
  'job you applied for',
  'recent activity in jobs you applied for',
  'new activity in jobs you applied for',
  'there has been recent activity in jobs you applied for',
  'next step in your application',
  'next steps of our hiring process',
  'next stage of our hiring process',
  'move forward with the hiring process',
  'selected to proceed',
  'selected to move forward',
  'invite you to an interview',
  'interview invitation',
  'interview schedule',
  'interview scheduled',
  'coding challenge',
  'technical assessment',
  'complete this assessment',
  'shortlisted',
  'we regret to inform you',
  'not be progressing with your application',
  'will not be moving forward',
  'other candidates were better aligned',
  'pleased to offer you',
  'offer letter',
  'background check',
  'pre-employment requirements',
  'onboarding'
];

const obviousNonApplication = [
  'job alert',
  'jobs alert',
  'daily job digest',
  'weekly job digest',
  'recommended jobs',
  'suggested jobs',
  'similar jobs',
  'jobs you may be interested in',
  'new jobs for you',
  'new job matches',
  'apply now to these jobs',
  'latest job openings',
  'latest vacancies',
  'vacancies this week',
  'newsletter',
  'manage preferences',
  'unsubscribe',
  'privacy notice',
  'privacy policy update',
  'terms of service update',
  'security alert',
  'password reset',
  'verify your email',
  'course enrollment',
  'enroll today',
  'promotional'
];

const knownRecruitingPlatform = [
  'indeed', 'linkedin', 'jobstreet', 'seek', 'onlinejobs',
  'greenhouse', 'lever', 'workable', 'ashby', 'smartrecruiters',
  'workday', 'jobvite', 'bamboohr', 'successfactors',
  'oraclecloud', 'icims', 'taleo', 'testgorilla', 'hirevue',
  'careers', 'recruit', 'talent'
].some(token => sender.includes(token));

const hasStrongApplicationEvidence =
  strongApplicationEvidence.some(phrase => text.includes(phrase));

const hasObviousNonApplicationEvidence =
  obviousNonApplication.some(phrase => text.includes(phrase));

const subjectLooksRecruitmentRelated =
  /\b(application|interview|assessment|offer|candidate|hiring|recruiter|recruitment|shortlisted)\b/i
    .test(subject);

let shouldUseAI = false;
let prefilterReason = '';

if (hasStrongApplicationEvidence) {
  shouldUseAI = true;
  prefilterReason = 'Clear application-lifecycle language was detected.';
} else if (hasObviousNonApplicationEvidence) {
  shouldUseAI = false;
  prefilterReason = 'The message appears to be a job alert, digest, newsletter, promotion, or unrelated notification.';
} else if (knownRecruitingPlatform && subjectLooksRecruitmentRelated) {
  shouldUseAI = true;
  prefilterReason = 'A known recruiting sender and a recruitment-related subject were detected.';
} else if (subjectLooksRecruitmentRelated) {
  shouldUseAI = true;
  prefilterReason = 'The subject may concern an existing application.';
} else {
  shouldUseAI = false;
  prefilterReason = 'No meaningful evidence of an existing application or application update was detected.';
}

return [{
  json: {
    ...item,
    senderName,
    subject,
    shouldUseAI,
    prefilterReason
  }
}];

const rows = $input.all();

function timestamp(item) {
  const value =
    item.json.internalDate ||
    item.json.date ||
    item.json.receivedDate ||
    0;

  const numeric = Number(value);
  if (Number.isFinite(numeric) && numeric > 0) {
    return numeric;
  }

  const parsed = new Date(value).getTime();
  return Number.isNaN(parsed) ? 0 : parsed;
}

rows.sort((a, b) => timestamp(a) - timestamp(b));
return rows;

return [{
  json: {
    success: true,
    message: 'The 90-day backfill completed and the Job Applications sheet was sorted newest-first.'
  }
}];

const item = $json;
const subject = String(item.subject || '');
const senderEmail = String(item.senderEmail || '').toLowerCase();
const body = String(item.cleanedEmailBody || item.emailBody || '');
const text = `${subject}\n${body}`;

const clean = value => String(value || '')
  .replace(/\s+/g, ' ')
  .replace(/^[\s:–—-]+|[\s:–—-]+$/g, '')
  .trim();

const dateOnly = value => {
  const parsed = new Date(value || '');
  return Number.isNaN(parsed.getTime()) ? '' : parsed.toISOString().slice(0, 10);
};

function inferBoard() {
  if (senderEmail.includes('indeed')) return 'Indeed';
  if (senderEmail.includes('linkedin')) return 'LinkedIn';
  if (senderEmail.includes('jobstreet')) return 'JobStreet';
  if (senderEmail.includes('seek')) return 'SEEK';
  if (senderEmail.includes('onlinejobs')) return 'OnlineJobs.ph';
  if (senderEmail.includes('greenhouse')) return 'Greenhouse';
  if (senderEmail.includes('lever')) return 'Lever';
  if (senderEmail.includes('workable')) return 'Workable';
  if (senderEmail.includes('ashby')) return 'Ashby';
  if (senderEmail.includes('smartrecruiters')) return 'SmartRecruiters';
  if (senderEmail.includes('workday')) return 'Workday';
  if (senderEmail.includes('jobvite')) return 'Jobvite';
  if (senderEmail.includes('bamboohr')) return 'BambooHR';
  if (senderEmail.includes('successfactors')) return 'SuccessFactors';
  if (senderEmail.includes('oracle')) return 'Oracle Careers';
  if (senderEmail.includes('icims')) return 'iCIMS';
  if (senderEmail.includes('taleo')) return 'Taleo';
  return '';
}

const normalized = text.toLowerCase();

const predictable = [
  'application submitted',
  'application received',
  'application confirmation',
  'your application was sent',
  'application was sent',
  'thank you for applying',
  'thanks for applying',
  'we received your application',
  'we have received your application',
  'successfully applied',
  'successfully submitted',
  'your application has been submitted',
  'your application has been received',
  'your application was successfully submitted'
].some(p => normalized.includes(p));

const complex = [
  'interview invitation',
  'interview scheduled',
  'invite you to an interview',
  'technical assessment',
  'coding challenge',
  'selected to proceed',
  'selected to move forward',
  'we regret to inform you',
  'not be progressing with your application',
  'will not be moving forward',
  'pleased to offer you',
  'offer letter',
  'background check',
  'onboarding',
  'shortlisted'
].some(p => normalized.includes(p));

let jobTitle = '';
let companyName = '';

const combinedPatterns = [
  /your application for\s+(.+?)\s+was successfully submitted to\s+([^\n|.]{2,160})/i,
  /your application for\s+(.+?)\s+has been submitted to\s+([^\n|.]{2,160})/i,
  /application for\s+(.+?)\s+was successfully submitted to\s+([^\n|.]{2,160})/i
];

for (const pattern of combinedPatterns) {
  const m = text.match(pattern);
  if (m) {
    jobTitle = clean(m[1]);
    companyName = clean(m[2]);
    break;
  }
}

jobTitle = jobTitle
  .replace(/\s+-\s+permanent.*$/i, '')
  .replace(/\s+\|\s+.*$/i, '')
  .trim();

companyName = companyName
  .replace(/\s+so you might.*$/i, '')
  .replace(/\s+each employer.*$/i, '')
  .trim();

const matched = predictable && !complex && Boolean(jobTitle) && Boolean(companyName);

if (!matched) {
  return [{
    json: {
      ...item,
      deterministicMatched: false,
      deterministicReason: complex
        ? 'A complex lifecycle update requires AI interpretation.'
        : 'The predictable parser could not confidently extract both company and job title.'
    }
  }];
}

return [{
  json: {
    ...item,
    deterministicMatched: true,
    deterministicReason: 'Predictable JobStreet confirmation parsed without AI.',
    deterministicOutput: {
      isJobApplicationEmail: true,
      confidence: 0.99,
      jobBoard: inferBoard(),
      companyName,
      jobTitle,
      jobDescription: '',
      salaryOffered: '',
      jobDatePosted: '',
      dateApplied: dateOnly(item.receivedDate),
      applicationStatus: 'Application Received',
      recruiterName: '',
      recruiterEmail: senderEmail,
      applicationUrl: '',
      reason: 'Predictable application confirmation parsed without AI.'
    }
  }
}];
